    const modMap = new Map();
    modMap.set(0, -1);
    const segments = [];
    const n = nums.length;

    for (let i = 0; i < n; i++) {
        prefixSum += nums[i];
        const mod = ((prefixSum % k) + k) % k;
        if (modMap.has(mod)) {
            segments.push([modMap.get(mod) + 1, i]);
        }
        modMap.set(mod, i);
    }

    segments.sort((a, b) => a[0] - b[0]);
    const merged = [];
    for (const [start, end] of segments) {
        if (merged.length === 0) {
            merged.push([start, end]);
        } else {
            const [lastStart, lastEnd] = merged[merged.length - 1];
            if (start > lastEnd) {
                merged.push([start, end]);
            } else {
                const newStart = Math.min(lastStart, start);
                const newEnd = Math.max(lastEnd, end);
                merged[merged.length - 1] = [newStart, newEnd];
            }
